import redis

def run_lua_script(redis_client, script_code, keys, args):
    """
    Executes a Lua script on the Redis server using redis.eval().

    Args:
        redis_client: An initialized Redis client instance.
        script_code: The Lua script as a string.
        keys: A list of keys that the script will access.
              These are passed as ARGV[1] to ARGV[#keys] in Lua.
        args: A list of additional arguments for the script.
              These are passed as ARGV[#keys + 1] to ARGV[#keys + #args] in Lua.

    Returns:
        The result of the Lua script execution.
    """
    try:
        result = redis_client.eval(script_code, len(keys), *keys, *args)
        return result
    except redis.exceptions.RedisError as e:
        print(f"Error executing Lua script: {e}")
        return None

